// Extract error details and the row number from the failed execution
const errorData = $input.first().json;

// The execution data contains the workflow data from when it failed
// We need to find the sheetRowNumber that was being processed
let sheetRowNumber = null;
let productName = 'Unknown';
let errorMessage = 'Unknown error';

// Extract error message
if (errorData.execution?.error?.message) {
  errorMessage = errorData.execution.error.message;
} else if (errorData.execution?.lastNodeExecuted) {
  errorMessage = `Failed at node: ${errorData.execution.lastNodeExecuted}`;
}

// Try to extract the row number from the execution data
// Walk through the execution's result data to find sheetRowNumber
try {
  const resultData = errorData.execution?.data?.resultData;
  if (resultData?.runData) {
    // Check nodes in reverse order to find the most recent data with sheetRowNumber
    const nodeNames = Object.keys(resultData.runData);
    for (const nodeName of nodeNames.reverse()) {
      const nodeRuns = resultData.runData[nodeName];
      if (nodeRuns && nodeRuns.length > 0) {
        const lastRun = nodeRuns[nodeRuns.length - 1];
        const outputData = lastRun?.data?.main?.[0];
        if (outputData && outputData.length > 0) {
          const jsonData = outputData[0]?.json;
          if (jsonData?.sheetRowNumber) {
            sheetRowNumber = jsonData.sheetRowNumber;
            productName = jsonData.productName || productName;
            break;
          }
        }
      }
    }
  }
} catch (e) {
  // If we can't extract row data, we'll log what we can
  errorMessage += ` (Could not determine sheet row: ${e.message})`;
}

return [{
  json: {
    sheetRowNumber: sheetRowNumber,
    productName: productName,
    errorMessage: errorMessage.substring(0, 500),
    failedNode: errorData.execution?.lastNodeExecuted || 'Unknown',
    executionId: errorData.execution?.id || 'Unknown',
    timestamp: new Date().toISOString()
  }
}];

// Log the error for cases where we couldn't determine the row
const item = $input.first().json;
console.warn('UGC Pipeline Error (unknown row):', JSON.stringify(item));

return [{
  json: {
    logged: true,
    ...item
  }
}];

const driveFile = $('Upload Video to Google Drive1').first().json;
const carried = $('Check Sora Status1').first().json;

const fileId = driveFile.id;
// Direct shareable link format
const videoUrl = `https://drive.google.com/file/d/${fileId}/view?usp=sharing`;

return [{
