    productName: carried.productName,
    description: carried.description,
    targetAudience: carried.targetAudience,
    sheetRowNumber: carried.sheetRowNumber,
    imageUrl: carried.imageUrl,
    videoUrl: videoUrl,
    videoId: carried.videoId,
    driveFileId: fileId
  }
}];

const raw = $input.first().json;
const response = Array.isArray(raw) ? raw[0] : raw;

// Get carried data from the job ID node
const carried = $('Extract Sora Job ID1').first().json;

const status = response.status || '';
const progress = response.progress || 0;
const pollCount = (carried.pollCount || 0) + 1;
const maxPolls = 40; // 20 minutes max

if (response.error) {
  throw new Error('Sora video generation failed: ' + JSON.stringify(response.error));
}

if (pollCount >= maxPolls) {
  throw new Error('Sora video generation timed out after ' + maxPolls + ' polls (20 minutes)');
}

return [{
