// Build a structured UGC video script for OpenAI Sora
const item = $input.first().json;

const product = item.productName || 'this product';
const description = item.description || '';
const audience = item.targetAudience || 'young adults';
const vision = item.visionAnalysis || {};

const mood = vision.mood || 'warm and authentic';
const colors = (vision.dominantColors || ['warm tones']).join(', ');
const lighting = vision.lighting || 'natural lighting';
const setting = vision.settingDetails || 'casual everyday setting';
const emotion = vision.emotionalTone || 'relatable';
const cameraMovements = (vision.suggestedCameraMovements || ['slow zoom in']).join(', ');

// Build a concise video prompt optimized for Sora
// Sora works best with clear, descriptive scene prompts rather than screenplay-style scripts
const videoScript = [
  `UGC-style smartphone video of ${audience} authentically using ${product} in ${setting}.`,
  description ? `The product is ${description}.` : '',
  `Visual style: ${mood} mood, ${colors} color palette, ${lighting}.`,
  `Camera: ${cameraMovements}, handheld smartphone feel.`,
  `The person picks up ${product} with genuine curiosity, uses it naturally, and reacts with authentic satisfaction.`,
  `Emotional tone: ${emotion}, relatable, candid.`,
  'Natural ambient lighting, shallow depth of field, no text overlays or logos.'
].filter(Boolean).join(' ');

return [{
  json: {
    ...item,
    videoScript: videoScript
  }
}];

// Parse GPT-4 Vision analysis and carry forward
const input = $input.first().json;
const prevData = $('Extract DALL-E URL1').first().json;

const content = input?.choices?.[0]?.message?.content || '{}';

let visionAnalysis;
try {
  // Strip markdown code fences if present
  const cleaned = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  visionAnalysis = JSON.parse(cleaned);
} catch (e) {
  // If JSON parsing fails, use raw text
  visionAnalysis = {
    mood: 'warm and authentic',
    dominantColors: ['warm tones'],
    composition: content,
    lighting: 'natural',
    subjectExpression: 'genuine',
    settingDetails: 'casual setting',
    suggestedCameraMovements: ['slow zoom in', 'pan across product'],
    emotionalTone: 'relatable'
  };
}

return [{
  json: {
    ...prevData,
    visionAnalysis: visionAnalysis
  }
}];

