// Build a UGC-style image generation prompt from product data
const item = $input.first().json;

const productName = item.productName || 'product';
const description = item.description || '';
const targetAudience = item.targetAudience || 'young adults';

// Construct a detailed DALL-E 3 prompt with UGC aesthetic
const prompt = [
  `A lifestyle photograph of ${productName} being used by ${targetAudience}.`,
  description ? `The product is ${description}.` : '',
  'Shot on iPhone, natural window lighting, casual home or cafe setting.',
  'UGC aesthetic: authentic, unposed, relatable feel.',
  'Warm color grading, shallow depth of field, genuine emotion.',
  'No text overlays, no logos, no watermarks.',
  'Photorealistic, editorial quality, candid moment.'
].filter(Boolean).join(' ');

return [{
  json: {
    ...item,
    imagePrompt: prompt
  }
}];

// Filter to only rows with Status = "Pending"
// n8n Google Sheets node returns rows with 0-based row_number
// but the actual sheet row is row_number + 2 (header row + 0-index offset)

const items = $input.all();
const pendingItems = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const status = (item.json['Status'] || '').toString().trim();

  if (status === 'Pending') {
    pendingItems.push({
      json: {
        productName: item.json['Product Name'] || '',
        description: item.json['Description'] || '',
        targetAudience: item.json['Target Audience'] || '',
        status: item.json['Status'] || '',
        imageUrl: item.json['Image URL'] || '',
        videoUrl: item.json['Video URL'] || '',
        errorMessage: item.json['Error Message'] || '',
        // row_number is the index in the sheet (0-based from data rows)
        // Actual sheet row = index + 2 (1 for header, 1 for 0-index)
        sheetRowNumber: i + 2
      }
    });
  }
}

if (pendingItems.length === 0) {
  // Return empty array — workflow stops naturally
  return [];
}

return pendingItems;
